"use client";

import { useEffect, useRef } from "react";
import WidthMark from "./WidthMark";

/**
 * Section 04 — certification. The verdict, set as wide as the standard
 * allows: STILL CORRECT runs the width axis 62 → 125 when the footer enters
 * the viewport, and the red certification rule draws itself underneath
 * (SVG pathLength trick, same as the hero stamp). Without JS — or under
 * reduced motion — the verdict simply stands, full width, rule complete.
 */
export default function Footer() {
  const footRef = useRef<HTMLElement | null>(null);

  useEffect(() => {
    const el = footRef.current;
    if (!el) return;
    if (!("IntersectionObserver" in window)) {
      el.classList.add("is-on");
      return;
    }
    const io = new IntersectionObserver(
      (hits) => {
        for (const hit of hits) {
          if (hit.isIntersecting) {
            el.classList.add("is-on");
            io.disconnect();
          }
        }
      },
      { threshold: 0.15 },
    );
    io.observe(el);
    return () => io.disconnect();
  }, []);

  return (
    <footer
      ref={footRef}
      className="raster-footer"
      aria-labelledby="raster-verdict"
    >
      <div className="raster-frame">
        <header className="raster-sechead">
          <span className="raster-sechead__no" aria-hidden="true">
            04
          </span>
          <p className="raster-sechead__title">
            certification{" "}
            <span lang="ko" className="raster-sechead__ko">
              인증
            </span>
          </p>
        </header>

        <h2
          className="raster-footer__verdict"
          id="raster-verdict"
          aria-label="STILL CORRECT — 지금도 유효함"
        >
          <WidthMark text="STILL CORRECT" />
        </h2>

        <svg
          className="raster-cert"
          viewBox="0 0 100 2"
          preserveAspectRatio="none"
          aria-hidden="true"
          focusable="false"
        >
          <line
            className="raster-cert__line"
            x1="0"
            y1="1"
            x2="100"
            y2="1"
            pathLength={1}
          />
        </svg>

        <p className="raster-footer__attest">
          examined at 6 and at 12 columns. re-examined annually since 1972.
          finding unchanged.
          <span lang="ko">
            6단과 12단에서 검수하였다. 1972년 이래 매년 재검수. 소견 변동 없음.
          </span>
        </p>

        <div className="raster-grid raster-footer__cols">
          <div className="raster-footer__block" data-flip>
            <h3 className="raster-footer__h raster-mono">bureau · 인증국</h3>
            <p>
              raster — bureau for grid systems
              <br />
              grid house, hallwylstrasse 04
              <br />
              ch-3005 bern
            </p>
            <p lang="ko">라스터 — 그리드 시스템 인증국</p>
          </div>
          <div className="raster-footer__block" data-flip>
            <h3 className="raster-footer__h raster-mono">hours · 응대</h3>
            <p>
              mon–fri, 08:30–17:00.
              <br />
              by appointment. bring your grid.
            </p>
            <p lang="ko">평일 08:30–17:00. 예약제. 그리드를 지참할 것.</p>
          </div>
          <div className="raster-footer__block" data-flip>
            <h3 className="raster-footer__h raster-mono">certificate · 인증서</h3>
            <p>
              certificate no. 0004-1972.
              <br />
              renewed annually. never amended.
            </p>
            <p lang="ko">인증서 제0004-1972호. 매년 갱신, 수정된 적 없음.</p>
          </div>
        </div>

        <p className="raster-footer__legal raster-mono">
          © 2026 raster — the grid does not negotiate.{" "}
          <span lang="ko">그리드는 협상하지 않는다.</span>
        </p>
      </div>
    </footer>
  );
}

"use client";

import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useRef,
  useState,
  type ReactNode,
} from "react";
import { flushSync } from "react-dom";
import { useFlip } from "../hooks/useFlip";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

export type GridCols = 6 | 12;

type GridContextValue = {
  cols: GridCols;
  setCols: (next: GridCols) => void;
};

const GridContext = createContext<GridContextValue>({
  cols: 12,
  setCols: () => undefined,
});

export function useGrid(): GridContextValue {
  return useContext(GridContext);
}

const TWELVE = Array.from({ length: 12 }, (_, i) => i);
const SIX = Array.from({ length: 6 }, (_, i) => i);

/**
 * Owns the certified column count. The default — and the static, no-JS
 * layout — is grid no. 04: twelve columns. `setCols` re-snaps every
 * `[data-flip]` element via FLIP (`flushSync` makes the layout change
 * synchronous between the two measurements); under reduced motion the
 * re-layout is instant.
 *
 * The provider also renders the exposed construction: two fixed column
 * overlays (12 and 6) that share the exact frame, gutter, and tracks of the
 * content grids. Only their opacity crosses — the hairlines redraw the
 * moment the law changes, and the content complies over 560 ms.
 */
export default function GridProvider({ children }: { children: ReactNode }) {
  const [cols, setColsState] = useState<GridCols>(12);
  const reduced = usePrefersReducedMotion();
  const scopeRef = useRef<HTMLDivElement | null>(null);
  const flip = useFlip(scopeRef);

  const setCols = useCallback(
    (next: GridCols) => {
      if (next === cols) return;
      if (reduced) {
        setColsState(next);
        return;
      }
      flip(() => {
        flushSync(() => setColsState(next));
      });
    },
    [cols, reduced, flip],
  );

  const value = useMemo(() => ({ cols, setCols }), [cols, setCols]);

  return (
    <GridContext.Provider value={value}>
      <div ref={scopeRef} className="raster-scope" data-grid={cols}>
        <div className="raster-overlay" aria-hidden="true">
          <div className="raster-overlay__layer raster-overlay__layer--twelve">
            {TWELVE.map((i) => (
              <span key={i} />
            ))}
          </div>
          <div className="raster-overlay__layer raster-overlay__layer--six">
            {SIX.map((i) => (
              <span key={i} />
            ))}
          </div>
        </div>
        {children}
      </div>
    </GridContext.Provider>
  );
}

type BlockTone = "ink" | "line" | "red";

type Block = {
  id: string;
  tone: BlockTone;
  size: "lg" | "md" | "sm" | "bar";
  /** span at 12 columns → span at 6 columns, printed on the block */
  spans: string;
};

const BLOCKS: Block[] = [
  { id: "a", tone: "ink", size: "lg", spans: "05 → 06" },
  { id: "b", tone: "line", size: "lg", spans: "07 → 03" },
  { id: "c", tone: "ink", size: "md", spans: "04 → 03" },
  { id: "d", tone: "red", size: "md", spans: "04 → 02" },
  { id: "e", tone: "ink", size: "md", spans: "04 → 02" },
  { id: "f", tone: "ink", size: "sm", spans: "09 → 02" },
  { id: "g", tone: "line", size: "sm", spans: "03 → 06" },
  { id: "h", tone: "ink", size: "bar", spans: "12 → 06" },
];

/**
 * Section 01 — the demonstration. A keyboard-operable segmented control
 * re-certifies the sheet at six or twelve columns; every block returns to a
 * lawful cell via the FLIP in useFlip.ts. The status line is a live region,
 * so the re-certification is announced, not just seen.
 */
export function GridToggle() {
  const { cols, setCols } = useGrid();

  return (
    <section className="raster-section" aria-labelledby="raster-demo-title">
      <div className="raster-frame">
        <header className="raster-sechead">
          <span className="raster-sechead__no" aria-hidden="true">
            01
          </span>
          <h2 className="raster-sechead__title" id="raster-demo-title">
            demonstration{" "}
            <span lang="ko" className="raster-sechead__ko">
              시연 — 재인증
            </span>
          </h2>
        </header>

        <div className="raster-grid raster-demo__lead">
          <div className="raster-demo__spec" data-flip>
            <p>
              the same content, certified twice: at six columns and at twelve.
              press the control; every block returns to a lawful cell.
              tolerance: 0 px.
            </p>
            <p lang="ko">
              동일한 내용을 6단과 12단으로 두 번 인증한다. 제어를 누르면 모든
              블록이 승인된 칸으로 복귀한다. 허용 오차: 0픽셀.
            </p>
          </div>

          <div
            className="raster-toggle"
            role="group"
            aria-label="column count — 단 수"
            data-flip
          >
            <span className="raster-toggle__label" aria-hidden="true">
              columns · 단
            </span>
            <div className="raster-toggle__btns">
              <button
                type="button"
                className="raster-toggle__btn"
                aria-pressed={cols === 6}
                onClick={() => setCols(6)}
              >
                06
              </button>
              <button
                type="button"
                className="raster-toggle__btn"
                aria-pressed={cols === 12}
                onClick={() => setCols(12)}
              >
                12
              </button>
            </div>
            <p className="raster-toggle__state" role="status">
              {cols === 12
                ? "certified: 12 columns — grid no. 04"
                : "certified: 6 columns — grid no. 02"}
            </p>
          </div>
        </div>

        <div className="raster-grid raster-demo__board">
          {BLOCKS.map((block) => (
            <div
              key={block.id}
              className={`raster-blk raster-blk--${block.id} raster-blk--${block.tone} raster-blk--${block.size}`}
              data-flip
            >
              <span className="raster-blk__meta">
                <span>mod. {block.id}</span>
                <span>{block.spans}</span>
              </span>
              {block.id === "a" ? (
                <span className="raster-blk__no" aria-hidden="true">
                  {cols === 12 ? "04" : "02"}
                </span>
              ) : null}
              {block.tone === "line" ? (
                <span className="raster-blk__bars" aria-hidden="true">
                  <i />
                  <i />
                  <i />
                </span>
              ) : null}
            </div>
          ))}
        </div>

        <p className="raster-demo__note raster-mono">
          fig. 01 — blocks are numbered, not named. spans are printed as
          12-col → 6-col.{" "}
          <span lang="ko">
            도판 01 — 블록에는 이름이 아니라 번호를 붙인다. 스팬은 12단 →
            6단으로 표기.
          </span>
        </p>
      </div>
    </section>
  );
}

"use client";

import { useEffect, useRef } from "react";
import WidthMark from "./WidthMark";
import { useGrid } from "./GridProvider";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

const CENTER_READOUT = "x 0.500 y 0.500 — certified center · 인증된 중심";

/**
 * Sheet 00 — the cover. The wordmark demonstrates the standard: Archivo's
 * width axis runs 62 → 125 per glyph on load (char-split, aria-safe), the
 * certification stamp draws itself in, and a crosshair instrument reports
 * raw pointer coordinates plus the column under the cursor.
 *
 * The instrument does not smooth its data — no lerp, no easing; it reports.
 * Fine pointers only: on touch, and under reduced motion, the crosshair
 * stands at the certified center of the sheet.
 */
export default function Hero() {
  const heroRef = useRef<HTMLElement | null>(null);
  const vlineRef = useRef<HTMLDivElement | null>(null);
  const hlineRef = useRef<HTMLDivElement | null>(null);
  const chipRef = useRef<HTMLDivElement | null>(null);
  const readRef = useRef<HTMLSpanElement | null>(null);
  const { cols } = useGrid();
  const reduced = usePrefersReducedMotion();

  // Arm the entrance animations (wordmark width axis, stamp line-draw).
  // Without JS the class never lands and the hero is simply complete.
  useEffect(() => {
    heroRef.current?.classList.add("is-on");
  }, []);

  useEffect(() => {
    const hero = heroRef.current;
    const vline = vlineRef.current;
    const hline = hlineRef.current;
    const chip = chipRef.current;
    const read = readRef.current;
    if (!hero || !vline || !hline || !chip || !read) return;
    if (reduced) return;
    if (!window.matchMedia("(hover: hover) and (pointer: fine)").matches) {
      return;
    }

    let raf = 0;
    let cx = 0;
    let cy = 0;

    const pad = (n: number) => String(Math.round(n)).padStart(4, "0");

    const update = () => {
      raf = 0;
      // One read, then writes — measured inside rAF, never during layout.
      const rect = hero.getBoundingClientRect();
      const x = Math.min(Math.max(cx - rect.left, 0), rect.width);
      const y = Math.min(Math.max(cy - rect.top, 0), rect.height);
      const col = Math.min(
        cols,
        Math.max(1, Math.ceil((x / rect.width) * cols)),
      );
      vline.style.transform = `translate3d(${x}px, 0, 0)`;
      hline.style.transform = `translate3d(0, ${y}px, 0)`;
      const chipX = Math.max(8, Math.min(x + 16, rect.width - 232));
      const chipY = Math.max(8, Math.min(y + 14, rect.height - 44));
      chip.style.transform = `translate3d(${chipX}px, ${chipY}px, 0)`;
      read.textContent = `x ${pad(x)} y ${pad(y)} — col ${String(col).padStart(2, "0")}/${cols}`;
    };

    const move = (e: PointerEvent) => {
      cx = e.clientX;
      cy = e.clientY;
      // First contact (or re-arm after a grid toggle while the pointer is
      // already inside): paint synchronously so the lines never flash at
      // the origin before the first rAF.
      if (!hero.classList.contains("is-live")) {
        hero.classList.add("is-live");
        update();
        return;
      }
      if (!raf) raf = requestAnimationFrame(update);
    };
    const leave = () => {
      hero.classList.remove("is-live");
      if (raf) {
        cancelAnimationFrame(raf);
        raf = 0;
      }
      vline.style.transform = "";
      hline.style.transform = "";
      chip.style.transform = "";
      read.textContent = CENTER_READOUT;
    };

    hero.addEventListener("pointermove", move);
    hero.addEventListener("pointerleave", leave);
    return () => {
      hero.removeEventListener("pointermove", move);
      hero.removeEventListener("pointerleave", leave);
      if (raf) cancelAnimationFrame(raf);
      hero.classList.remove("is-live");
      vline.style.transform = "";
      hline.style.transform = "";
      chip.style.transform = "";
      read.textContent = CENTER_READOUT;
    };
  }, [reduced, cols]);

  return (
    <header
      ref={heroRef}
      className="raster-hero"
      aria-labelledby="raster-title"
    >
      <div className="raster-frame raster-hero__inner">
        <p className="raster-hero__kicker raster-mono">
          <span>raster — bureau for grid systems · est. 1957</span>
          <span lang="ko">라스터 — 그리드 시스템 인증국</span>
          <span>standard sheet no. 10 · 표준 명세 제10호</span>
        </p>

        <h1 className="raster-hero__title" id="raster-title" aria-label="RASTER">
          <WidthMark text="RASTER" />
        </h1>

        <p className="raster-hero__sub" lang="ko">
          그리드 시스템 인증국
        </p>

        <div className="raster-grid raster-hero__foot">
          <div className="raster-hero__spec" data-flip>
            <p>
              grid no. 04. approved 1972. still correct.
              <span lang="ko">그리드 제4호. 1972년 승인. 지금도 유효함.</span>
            </p>
            <p>
              clause 1.1 — a grid is correct, or it is not a grid.
              <span lang="ko">
                제1조 1항 — 그리드는 정확하거나, 그리드가 아니다.
              </span>
            </p>
            <p>
              this sheet is set on grid no. 04. deviations: none recorded.
              <span lang="ko">
                본 명세서는 그리드 제4호 위에 조판되었다. 이탈: 기록된 바 없음.
              </span>
            </p>
          </div>

          <div className="raster-hero__stampcell" data-flip>
            {/* Decorative seal: the accessible certification claim is the
                spec text beside it, so the stamp stays aria-hidden. */}
            <svg
              className="raster-stamp"
              viewBox="0 0 132 132"
              aria-hidden="true"
              focusable="false"
            >
              <circle
                className="raster-stamp__draw"
                cx="66"
                cy="66"
                r="62"
                pathLength={1}
              />
              <circle
                className="raster-stamp__draw raster-stamp__draw--d2"
                cx="66"
                cy="66"
                r="44"
                pathLength={1}
              />
              <line
                className="raster-stamp__draw raster-stamp__draw--d3"
                x1="66"
                y1="4"
                x2="66"
                y2="18"
                pathLength={1}
              />
              <line
                className="raster-stamp__draw raster-stamp__draw--d3"
                x1="66"
                y1="114"
                x2="66"
                y2="128"
                pathLength={1}
              />
              <line
                className="raster-stamp__draw raster-stamp__draw--d3"
                x1="4"
                y1="66"
                x2="18"
                y2="66"
                pathLength={1}
              />
              <line
                className="raster-stamp__draw raster-stamp__draw--d3"
                x1="114"
                y1="66"
                x2="128"
                y2="66"
                pathLength={1}
              />
              <text className="raster-stamp__txt" x="66" y="56">
                RASTER
              </text>
              <text className="raster-stamp__txt" x="66" y="72">
                NO. 04 — 1972
              </text>
              <text className="raster-stamp__txt" x="66" y="88">
                인증필
              </text>
            </svg>
          </div>
        </div>

        <p className="raster-hero__cue raster-mono" aria-hidden="true">
          begin inspection ↓ 검수 시작
        </p>
      </div>

      {/* The instrument. Purely decorative; centered without a fine pointer. */}
      <div className="raster-cross" aria-hidden="true">
        <div ref={vlineRef} className="raster-cross__v" />
        <div ref={hlineRef} className="raster-cross__h" />
        <div ref={chipRef} className="raster-cross__chip">
          <span ref={readRef}>{CENTER_READOUT}</span>
        </div>
      </div>
    </header>
  );
}

"use client";

import { useEffect, useRef } from "react";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

/**
 * Section 02 — the modular scale in motion. Six steps of a 1.333 (perfect
 * fourth) scale. Each word's font-size is already its certified value; what
 * scroll drives is a `transform: scale()` from exactly one step below
 * (1 / 1.333 ≈ 0.75) up to 1 — so every heading *arrives* at its size by
 * traveling the ratio itself, and the compositor does all the work.
 *
 * Reads happen inside rAF (one getBoundingClientRect per scroll frame),
 * then writes — no layout thrash. Reduced motion, and no-JS, render the
 * settled scale: transforms only ever exist as inline styles set here.
 */

const RATIO = 1.333;
const S0 = 1 / RATIO;

const STEPS = [
  { step: 0, pow: "×1.333⁰ = 1.000", en: "annotation", ko: "주석" },
  { step: 1, pow: "×1.333¹ = 1.333", en: "body copy", ko: "본문" },
  { step: 2, pow: "×1.333² = 1.777", en: "subheading", ko: "소제목" },
  { step: 3, pow: "×1.333³ = 2.369", en: "heading", ko: "표제" },
  { step: 4, pow: "×1.333⁴ = 3.157", en: "display", ko: "대형" },
  { step: 5, pow: "×1.333⁵ = 4.209", en: "monument", ko: "기념비" },
];

const SETTLED = "t = 1.000 — settled · 정착";

export default function ModularScale() {
  const sectionRef = useRef<HTMLElement | null>(null);
  const chipRef = useRef<HTMLParagraphElement | null>(null);
  const reduced = usePrefersReducedMotion();

  useEffect(() => {
    const section = sectionRef.current;
    const chip = chipRef.current;
    if (!section || !chip) return;
    const words = Array.from(
      section.querySelectorAll<HTMLElement>("[data-ms-word]"),
    );

    if (reduced) {
      for (const el of words) {
        el.style.transform = "";
        el.style.opacity = "";
      }
      chip.textContent = SETTLED;
      return;
    }

    let raf = 0;
    const clamp01 = (n: number) => Math.min(1, Math.max(0, n));

    const update = () => {
      raf = 0;
      // Single read per frame; everything after is writes.
      const rect = section.getBoundingClientRect();
      const vh = window.innerHeight;
      if (rect.top > vh * 1.6 || rect.bottom < -vh * 0.6) return;
      const total = rect.height + vh * 0.4;
      const p = clamp01((vh * 0.92 - rect.top) / total);
      words.forEach((el, i) => {
        const local = clamp01((p - i * 0.09) / 0.5);
        const eased = local * local * (3 - 2 * local); // smoothstep
        const s = S0 + (1 - S0) * eased;
        el.style.transform = `scale(${s.toFixed(4)})`;
        el.style.opacity = (0.3 + 0.7 * eased).toFixed(3);
      });
      chip.textContent = p >= 1 ? SETTLED : `t = ${p.toFixed(3)} — interpolating · 보간 중`;
    };

    const schedule = () => {
      if (!raf) raf = requestAnimationFrame(update);
    };

    schedule();
    window.addEventListener("scroll", schedule, { passive: true });
    window.addEventListener("resize", schedule);
    return () => {
      window.removeEventListener("scroll", schedule);
      window.removeEventListener("resize", schedule);
      if (raf) cancelAnimationFrame(raf);
    };
  }, [reduced]);

  return (
    <section
      ref={sectionRef}
      className="raster-section"
      aria-labelledby="raster-ms-title"
    >
      <div className="raster-frame">
        <header className="raster-sechead">
          <span className="raster-sechead__no" aria-hidden="true">
            02
          </span>
          <h2 className="raster-sechead__title" id="raster-ms-title">
            modular scale{" "}
            <span lang="ko" className="raster-sechead__ko">
              모듈러 스케일
            </span>
          </h2>
          <p className="raster-ms__chip raster-mono" ref={chipRef} aria-hidden="true">
            {SETTLED}
          </p>
        </header>

        <div className="raster-grid">
          <div className="raster-ms__intro" data-flip>
            <p>
              ratio 1.333 — the perfect fourth. approved 1957. sizes are not
              chosen; they are derived.
              <span lang="ko">
                비율 1.333 — 완전4도. 1957년 승인. 크기는 고르는 것이 아니라
                도출하는 것이다.
              </span>
            </p>
            <p>
              between steps there is nothing. a size off the scale is not a
              size.
              <span lang="ko">
                단계 사이에는 아무것도 없다. 스케일을 벗어난 크기는 크기가
