  --raster-font-mono: var(--font-space-mono), var(--font-plex-kr), "Courier New", monospace;

  /* -- the certified construction ---------------------------------------- */
  --raster-maxw: 1440px;
  --raster-margin: clamp(16px, 4vw, 48px);
  --raster-gutter: clamp(8px, 1.6vw, 24px);
  --raster-baseline: 24px;

  /* -- motion: brisk, no overshoot — the bureau does not bounce ----------- */
  --raster-ease: cubic-bezier(0.2, 0, 0, 1);
  --raster-flip-ms: 560ms;

  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  background: var(--raster-paper);
  color: var(--raster-ink);
  font-family: var(--raster-font-stack);
  font-size: clamp(15px, 0.4vw + 13.6px, 17px);
  font-variation-settings: "wdth" 100;
