}

/* -- the specimen blocks: 12-col spans → 6-col spans ----------------------
   12: [a5 b7] [c4 d4 e4] [f9 g3] [h12]
    6: [a6] [b3 c3] [d2 e2 f2] [g6] [h6] */

.raster-blk {
  position: relative;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  gap: 12px;
  padding: 12px 14px;
}

.raster-blk--ink {
  background: var(--raster-ink);
  color: var(--raster-paper);
}

.raster-blk--red {
  background: var(--raster-red);
  color: #ffffff; /* 4.9:1 on the red — AA for the block labels */
}

.raster-blk--line {
  border: 1px solid var(--raster-ink);
}

.raster-blk--lg {
  min-height: clamp(150px, 24vw, 240px);
}

.raster-blk--md {
  min-height: clamp(104px, 15vw, 156px);
}

.raster-blk--sm {
  min-height: clamp(64px, 9vw, 96px);
}

.raster-blk--bar {
  min-height: 56px;
}

.raster-blk__meta {
  display: flex;
  justify-content: space-between;
  gap: 8px;
  font-family: var(--raster-font-mono);
  font-size: 0.66rem;
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.04em;
}

.raster-blk__no {
  align-self: flex-end;
  font-size: clamp(2.6rem, 6.5vw, 5.4rem);
  font-weight: 640;
  font-variation-settings: "wdth" 125;
  line-height: 0.85;
}

.raster-blk__bars {
  display: grid;
  gap: 7px;
}

.raster-blk__bars i {
  height: 2px;
  background: rgba(17, 17, 17, 0.35);
}

.raster-blk__bars i:nth-child(2) {
  width: 84%;
}

.raster-blk__bars i:nth-child(3) {
  width: 58%;
}

.raster-blk--a { grid-column: span 5; }
.raster-blk--b { grid-column: span 7; }
.raster-blk--c { grid-column: span 4; }
.raster-blk--d { grid-column: span 4; }
.raster-blk--e { grid-column: span 4; }
.raster-blk--f { grid-column: span 9; }
.raster-blk--g { grid-column: span 3; }
.raster-blk--h { grid-column: span 12; }

[data-grid="6"] .raster-blk--a { grid-column: span 6; }
[data-grid="6"] .raster-blk--b { grid-column: span 3; }
[data-grid="6"] .raster-blk--c { grid-column: span 3; }
[data-grid="6"] .raster-blk--d { grid-column: span 2; }
[data-grid="6"] .raster-blk--e { grid-column: span 2; }
[data-grid="6"] .raster-blk--f { grid-column: span 2; }
[data-grid="6"] .raster-blk--g { grid-column: span 6; }
[data-grid="6"] .raster-blk--h { grid-column: span 6; }

.raster-demo__note {
  margin: 18px 0 0;
  color: var(--raster-ink-dim);
}

/* ==========================================================================
   02 · Modular scale
   ========================================================================== */

.raster-ms__chip {
  margin: 0 0 0 auto;
  align-self: baseline;
  border: 1px solid var(--raster-ink);
  padding: 3px 10px;
  min-width: 21ch;
  text-align: left;
}

.raster-ms__intro {
  grid-column: 1 / span 4;
}

[data-grid="6"] .raster-ms__intro {
  grid-column: 1 / span 6;
}

.raster-ms__intro p {
  margin: 0 0 12px;
  font-size: clamp(0.95rem, 1.4vw, 1.15rem);
  line-height: 1.45;
  max-width: 44ch;
}

.raster-ms__intro p span[lang="ko"] {
  display: block;
  margin-top: 2px;
  font-size: 0.9em;
  color: var(--raster-ink-dim);
}

.raster-ms__list {
  grid-column: 5 / span 8;
  margin: 0;
  padding: 0;
  list-style: none;
  --raster-msb: clamp(0.95rem, 0.5vw + 0.8rem, 1.15rem);
}

[data-grid="6"] .raster-ms__list {
  grid-column: 1 / span 6;
  margin-top: clamp(20px, 4vh, 36px);
}

.raster-ms__row {
  display: grid;
  grid-template-columns: clamp(9rem, 16vw, 13rem) minmax(0, 1fr);
  align-items: baseline;
  gap: 8px 18px;
  padding-block: 14px 12px;
  border-bottom: 1px solid var(--raster-rule-soft);
}

.raster-ms__row:first-child {
  border-top: 1.5px solid var(--raster-ink);
}

.raster-ms__ann {
  color: var(--raster-ink-dim);
}

.raster-ms__word {
  display: inline-block;
  transform-origin: 0% 70%;
  font-weight: 620;
  font-variation-settings: "wdth" 116;
  letter-spacing: -0.01em;
  line-height: 1.05;
}

.raster-ms__word :lang(ko) {
  font-weight: 500;
  font-size: 0.82em;
}

.raster-ms__word--0 { font-size: var(--raster-msb); }
.raster-ms__word--1 { font-size: calc(var(--raster-msb) * 1.333); }
.raster-ms__word--2 { font-size: calc(var(--raster-msb) * 1.777); }
.raster-ms__word--3 { font-size: calc(var(--raster-msb) * 2.369); }
.raster-ms__word--4 { font-size: calc(var(--raster-msb) * 3.157); }
.raster-ms__word--5 { font-size: calc(var(--raster-msb) * 4.209); }

/* ==========================================================================
   03 · Registry — the specimen table
   ========================================================================== */

.raster-tablewrap {
  grid-column: 2 / span 10;
  overflow-x: auto;
}

[data-grid="6"] .raster-tablewrap {
  grid-column: 1 / span 6;
}

.raster-table {
  width: 100%;
  min-width: 560px;
  border-collapse: collapse;
  border-top: 3px solid var(--raster-ink);
}

.raster-table caption {
  text-align: left;
  padding: 10px 0;
  color: var(--raster-ink-dim);
  caption-side: top;
}

.raster-table th,
.raster-table td {
  padding: 12px 14px;
  text-align: left;
  vertical-align: baseline;
}

.raster-table thead th {
  border-top: 1.5px solid var(--raster-ink);
  border-bottom: 1.5px solid var(--raster-ink);
  font-family: var(--raster-font-mono);
  font-size: 0.66rem;
  font-weight: 700;
  letter-spacing: 0.06em;
}

.raster-table tbody th,
.raster-table tbody td {
  border-bottom: 1px solid var(--raster-rule-soft);
  font-size: 0.92rem;
}

.raster-table tbody th {
  font-weight: 700;
}

.raster-td--num {
  text-align: right;
}

.raster-table .raster-mono {
  font-size: 0.8rem;
}

/* status marks: red geometry; the meaning is always in the black text */
.raster-status {
  position: relative;
  display: inline-flex;
  align-items: center;
  gap: 10px;
  white-space: nowrap;
}

.raster-status i {
  position: relative;
  width: 10px;
  height: 10px;
  flex: none;
  background: var(--raster-red);
}

.raster-status--rev i {
  background: transparent;
  box-shadow: inset 0 0 0 1.5px var(--raster-red);
}

.raster-status--dep i {
  background: transparent;
}

.raster-status--dep i::before,
.raster-status--dep i::after {
  content: "";
  position: absolute;
  left: -2px;
  top: 4px;
  width: 14px;
  height: 2px;
  background: var(--raster-red);
  transform: rotate(45deg);
}

.raster-status--dep i::after {
  transform: rotate(-45deg);
}

.raster-status--star {
  font-weight: 700;
}

.raster-row--dep th {
  box-shadow: inset 3px 0 0 var(--raster-red);
}

.raster-table__note {
  margin: 14px 0 0;
  color: var(--raster-ink-dim);
}

/* ==========================================================================
   04 · Footer — certification
   ========================================================================== */

.raster-footer {
  padding-block: clamp(64px, 10vh, 120px) 28px;
}

.raster-footer__verdict {
  margin: clamp(20px, 4vh, 44px) 0 16px;
  font-size: clamp(2.3rem, 9.2vw, 9.6rem);
  font-weight: 640;
  letter-spacing: -0.015em;
  line-height: 0.92;
  text-transform: uppercase;
}

.raster-cert {
  display: block;
  width: 100%;
  height: 3px;
}

.raster-cert__line {
  fill: none;
  stroke: var(--raster-red);
  stroke-width: 3;
}

.raster-js .is-on .raster-cert__line {
  stroke-dasharray: 1;
  stroke-dashoffset: 1;
  animation: raster-draw 1100ms var(--raster-ease) 480ms forwards;
}

.raster-footer__attest {
  margin: 18px 0 0;
  font-size: clamp(0.95rem, 1.4vw, 1.15rem);
  line-height: 1.45;
  max-width: 58ch;
}

.raster-footer__attest span[lang="ko"] {
  display: block;
  margin-top: 2px;
  font-size: 0.9em;
  color: var(--raster-ink-dim);
}

.raster-footer__cols {
  margin-top: clamp(40px, 7vh, 72px);
}

.raster-footer__block {
  grid-column: span 4;
  border-top: 1px solid var(--raster-ink);
  padding-top: 12px;
}

[data-grid="6"] .raster-footer__block {
  grid-column: span 2;
}

.raster-footer__h {
  margin: 0 0 10px;
  font-weight: 700;
}

.raster-footer__block p {
  margin: 0 0 8px;
  font-size: 0.92rem;
  line-height: 1.5;
}

.raster-footer__legal {
  margin: clamp(48px, 8vh, 80px) 0 0;
  border-top: 1px solid var(--raster-rule-soft);
  padding-top: 14px;
}

/* ==========================================================================
   Small sheets — the grid holds; the furniture stacks
   (kept below the [data-grid] overrides so equal-specificity rules win)
   ========================================================================== */

@media (max-width: 860px) {
  .raster-scope .raster-hero__spec,
  .raster-scope .raster-hero__stampcell,
  .raster-scope .raster-demo__spec,
  .raster-scope .raster-toggle,
  .raster-scope .raster-ms__intro,
  .raster-scope .raster-ms__list,
  .raster-scope .raster-tablewrap,
  .raster-scope .raster-footer__block {
    grid-column: 1 / -1;
  }

  .raster-scope .raster-hero__stampcell {
    justify-self: start;
  }

  .raster-scope .raster-ms__list {
    margin-top: clamp(20px, 4vh, 36px);
  }

  .raster-ms__row {
    grid-template-columns: minmax(0, 1fr);
  }

  .raster-ms__chip {
    margin-left: 0;
    flex-basis: 100%;
  }
}

/* touch / coarse pointers: the instrument stands at the certified center
   (the JS never arms itself without a fine pointer) */
@media (hover: none), (pointer: coarse) {
  .raster-cross {
    opacity: 0.4;
  }
}

/* ==========================================================================
   Reduced motion — the finished document, immediately
   ========================================================================== */

@media (prefers-reduced-motion: reduce) {
  .raster-root *,
  .raster-root *::before,
  .raster-root *::after {
    animation: none !important;
    transition: none !important;
  }

  /* line-draw strokes must render complete, not paused at zero */
  .raster-root .raster-stamp__draw,
  .raster-root .raster-cert__line {
    stroke-dasharray: none !important;
    stroke-dashoffset: 0 !important;
  }
}
